// CTA Section helper
function renderCTA($title = null, $desc = null) {
  $WHATSAPP = "https://wa.me/5511940449696?text=Ol%C3%A1%2C%20gostaria%20de%20falar%20com%20um%20especialista.";
  $t = $title ?: 'Pronto para proteger seu negócio?';
  $d = $desc ?: 'Agende uma consulta com nossos especialistas e descubra como podemos ajudar sua empresa.';
  echo '<section class="cta-section">
    <div class="container" style="padding:0 1.25rem">
      <h2>'.$t.'</h2>
      <p>'.$d.'</p>
      <div class="cta-buttons">
        <a href="'.$WHATSAPP.'" target="_blank" rel="noopener noreferrer" class="btn btn-accent btn-lg">'.icon('phone',16).' Falar com Advogado →</a>
        <a href="tel:+5511974083838" class="btn btn-outline btn-lg">'.icon('message',16).' (11) 94044-9696</a>
      </div>
      <div class="cta-indicators">
        <span>'.icon('clock',16).' Resposta em até 24h</span>
        <span>'.icon('check',16).' Atendimento disponível</span>
      </div>
    </div>
  </section>';
}
